export interface ActivityState {
  currentApp: string
  isActive: boolean
  recentApps: string[]
  lastActivityTimestamp: number
}

constructor(options: ActivityMonitorOptions) {
  this.aggregationIntervalMs = options.aggregationIntervalMs ?? DEFAULT_AGGREGATION_INTERVAL_MS
  this.inactivityThresholdMs = options.inactivityThresholdMs ?? DEFAULT_INACTIVITY_THRESHOLD_MS
  this.maxRecentApps = options.maxRecentApps ?? DEFAULT_MAX_RECENT_APPS
  this.eventRetentionMs = options.eventRetentionMs ?? DEFAULT_EVENT_RETENTION_MS
}

findings.suggestion:
Add validation in the constructor:

const interval = options.aggregationIntervalMs ?? DEFAULT_AGGREGATION_INTERVAL_MS
if (interval <= 0 || !Number.isFinite(interval)) {
  throw new Error(`aggregationIntervalMs must be a positive finite number, got ${interval}`)
}

Alternatively, use a Valibot schema for ActivityMonitorOptions to validate at the boundary (project standard).

Introduce branded types:

type TimestampMs = number & { readonly __brand: unique symbol }
type DurationMs = number & { readonly __brand: unique symbol }

With factory functions: const toTimestampMs = (n: number): TimestampMs => n as TimestampMs

This is a recurring pattern across the codebase (flagged in prior reviews). Consider creating a shared types/branded.ts module.
